490	  async getItemInfo() {
491	    if (!this.itemData || !this.itemData[0]) {
492	      return;
493	    }
494	
495	    const currentItem = this.itemData[0];
496	    const isOldItem = currentItem.is_item_old === true;
497	    this.applyProductAssignmentsFromItem(currentItem.productUserAssignments || []);
498	
499	
500	    const isSpruceNonLic = currentItem.div_code_fk === 9;
501	
502	    // Helper function to select based on item age
503	    const selectOption = (options, codeKey, idKey, applyYearCheck = false) => {
504	      return options.find((x) =>
505	        isOldItem
506	          ? x.mg_code === currentItem[codeKey] &&
507	          !x.is_active &&
508	          (!applyYearCheck || x.created_year !== 2025)
509	          : x.id === currentItem[idKey]
510	      );
511	    };
512	
513	    // Merchgroup selections
