932	  /**
933	   * Production milestone timeline derived from the item's real date fields.
934	   * Each milestone is `done` (date in the past), `current` (next upcoming /
935	   * first without a past date) or `todo`.
936	   */
937	  get timelineItems(): { label: string; date: any; state: 'done' | 'current' | 'todo' }[] {
938	    const ci = this.itemData?.[0];
939	    if (!ci) return [];
940	    const points = [
941	      { label: 'Created', date: ci.created_time_date },
942	      { label: 'Test Report', date: ci.udf_date02 },
943	      { label: 'Photography', date: ci.udf_date03 },
944	      { label: 'Due', date: ci.due_date },
945	      { label: 'On Shelf', date: ci.udf_date01 },
946	    ];
947	    const now = Date.now();
948	    let currentAssigned = false;
949	    return points.map((p) => {
950	      const t = p.date ? new Date(p.date).getTime() : NaN;
951	      let state: 'done' | 'current' | 'todo';
952	      if (!isNaN(t) && t < now) {
953	        state = 'done';
954	      } else if (!currentAssigned) {
955	        state = 'current';
956	        currentAssigned = true;
957	      } else {
958	        state = 'todo';
959	      }
960	      return { label: p.label, date: p.date, state };
961	    });
962	  }
