92	    if (extension === 'ai') {
93	      fileName = `${new Date().getTime()}-${file.name.toLowerCase().replace('.ai', '.pdf')}`;
94	      contentType = 'application/pdf';
95	    } else if (['ai', 'pdf'].includes(extension)) {
96	      fileName = `${new Date().getTime()}-${file.name.toLowerCase()}`;
97	    } else {
98	      fileName = 'images-' + `${new Date().getTime()}-${file.name.toLowerCase()}`;
99	    }
100	    
101	    this.isLoading = true;
102	    
103	    this.itemService
104	      .getPreSignedUrl({ fileName, contentType })
105	      .subscribe((res: { signedUrl: string }) => {
106	        const signedUrl = res.signedUrl;
107	        const headers = new Headers({ 
108	          'Content-Type': contentType, 
109	          'x-amz-acl': 'public-read' 
110	        });
111	        
112	        const putConfig = { 
113	          method: 'PUT', 
114	          body: file, 
115	          headers: headers 
116	        };
117	        
118	        fetch(signedUrl, putConfig)
119	          .then(async output => {
120	            if (!this.data.itemId) {
121	              const sharedLink = this.helperService.buildPublicUrl(fileName);
122	              const thumbName = `thumbs-${fileName.replace('images-', '')}`;
123	              const thumbFile = await this.helperService.resizeImage(file, thumbName);
124	              await this.helperService.saveToDigitalOceanAndDB(thumbName, contentType, thumbFile);
125	              const thumbSharedLink = this.helperService.buildPublicUrl(thumbName);
126	              
127	              this.isLoading = false;
128	              return this.dialogRef.close({ sharedLink, thumbSharedLink });
129	            }
130	            
131	            const body = this.data.value === 'rfq'
132	              ? { flag: 'rfq-update', fileName }
133	              : {
134	                  flag: 'item-attachment-create',
135	                  item_num_id_fk: this.data.itemId,
136	                  attachment_type: contentType,
137	                  attachment_display_name: contentType.split("/")[0],
138	                  fileName
139	                };
140	            
141	            this.itemService
142	              .saveTechLink(body, this.data.itemId)
143	              .pipe(take(1))
144	              .subscribe((res: { sharedLink: string }) => {
145	                this.isLoading = false;
146	                this.dialogRef.close(res.sharedLink);
147	              });
148	          })
149	          .catch(error => {
150	            this.isLoading = false;
151	            this._snackBar.open("Upload failed!", 'Close', {
152	              duration: 2000,
153	            });
154	            console.error('Upload error:', error);
155	          });
156	      });
157	  }
158	}

