894		private setupItemTypeSearch(): void {
895			this.itemTypeSearchSub?.unsubscribe();
896			this.itemTypeSearchSub = this.itemTypeControl.valueChanges.pipe(
897				map(value => this.getItemTypeSearchTerm(value)),
898				debounceTime(250),
899				distinctUntilChanged(),
900				switchMap((query) => {
901					const normalizedQuery = query.trim();
902					if (normalizedQuery.length === 1) {
903						return of(null);
904					}
905	
906					this.itemTypeLoading = true;
907					return this.fetchItemTypeOptions(normalizedQuery).pipe(
908						finalize(() => {
909							this.itemTypeLoading = false;
910						})
911					);
912				})
913			).subscribe((options) => {
914				if (!options) return;
915				this.itemTypeOptions = options;
916				this.syncSelectedItemType();
917			});
918		}
