45	  onFileChange(pFileList: File[] | FileList) {
46	    const fileList = pFileList instanceof FileList ? Array.from(pFileList) : pFileList;
47	    if (fileList.length > 0) {
48	      this.file = fileList[0];
49	      this.uploadState = 'loading';
50	      
51	      const reader = new FileReader();
52	      reader.onload = (e: any) => {
53	        this.thumbnailPreview = this.sanitizer.bypassSecurityTrustUrl(e.target.result);
54	        this.onSave();
55	      };
56	      reader.onerror = () => {
57	        this.uploadState = 'error';
58	      };
59	      reader.readAsDataURL(this.file);
60	    }
61	  }
