63	  onSave() {
64	    if (!this.file) return;
65	
66	    let contentType = this.file.type;
67	    const extension = this.file.name.split('.').pop().toLowerCase();
68	    let fileName = `images-${new Date().getTime()}-${this.file.name.toLowerCase()}`;
69	
70	    if (extension === 'ai') {
71	      fileName = `${new Date().getTime()}-${this.file.name.toLowerCase().replace('.ai', '.pdf')}`;
72	      contentType = 'application/pdf';
73	    } else if (['pdf'].includes(extension)) {
74	      fileName = `${new Date().getTime()}-${this.file.name.toLowerCase()}`;
75	    }
76	
77	    this.itemService.getPreSignedUrl({ fileName, contentType }).subscribe({
78	      next: (res: { signedUrl: string }) => {
79	        const { signedUrl } = res;
80	        const headers = new Headers({ 'Content-Type': contentType, 'x-amz-acl': 'public-read' });
81	        
82	        fetch(signedUrl, { method: 'PUT', body: this.file, headers })
83	          .then(async () => {
84	            const sharedLink = this.helperService.buildPublicUrl(fileName);
85	            const thumbName = `thumbs-${fileName.replace('images-', '')}`;
86	            const thumbFile = await this.helperService.resizeImage(this.file, thumbName);
87	            await this.helperService.saveToDigitalOceanAndDB(thumbName, contentType, thumbFile);
88	            const thumbSharedLink = this.helperService.buildPublicUrl(thumbName);
89	            
90	            this.uploadState = 'preview';
91	            this.uploadComplete.emit({ sharedLink, thumbSharedLink });
92	          })
93	          .catch(() => this.handleUploadError());
94	      },
95	      error: () => this.handleUploadError()
96	    });
97	  }
